import {React , useState, useEffect } from "react";
import './Design.css';


function theme(){
    const[themes,setThemes]=useState([]);
useEffect(()=>{
    fetch("http://localhost:8080/admin/viewTheme")
    .then(res=>res.json())
    .then((result)=>{
      setThemes(result);
    }
  )
  })

  return <>
  <select id="themename">
{themes.map(theme => {
        return(<option value={theme.themeName} > {theme.themeName}</option>)
    })}
</select>

  </>
}
export default theme;
